parameters.jsCode:
const item = $input.item.json;

const bio = (item['Bio'] || '').trim();
const statement = (item['Artist Statement'] || '').trim();

function isGibberish(text) {
  if (!text || text.length < 10) return true;
  const lower = text.toLowerCase();
  if (lower.includes('lorem ipsum')) return true;
  if (lower.includes('dolor sit amet')) return true;
  if (/^(test|asdf|xxx|placeholder|tbd|n\/a|none|na)$/i.test(lower)) return true;
  return false;
}

const bioIsGibberish = isGibberish(bio);
const statementIsGibberish = isGibberish(statement);
const bioIsShort = bio.length > 0 && bio.length < 50 && !bioIsGibberish;

const email = (item['Email'] || '').trim().toLowerCase();
const website = (item['Website'] || '').trim().toLowerCase();
const city = (item['City'] || '').trim();
const state = (item['State'] || '').trim();

let emailDomain = '';
if (email && email.includes('@')) {
  emailDomain = email.split('@')[1];
  const generic = ['gmail.com','yahoo.com','hotmail.com','outlook.com','aol.com','icloud.com','mac.com','me.com','protonmail.com','live.com'];
  if (generic.includes(emailDomain)) emailDomain = '';
}

// String-based URL parsing (new URL() not available in n8n Code node sandbox)
let websiteDomain = '';
if (website) {
  let w = website;
  w = w.replace(/^https?:\/\//, '');  // strip protocol
  w = w.replace(/\/.*$/, '');          // strip path
  w = w.replace(/^www\./, '');         // strip www.
  websiteDomain = w.toLowerCase();
}

let quality = 5;
if (bioIsGibberish) quality -= 3;
if (statementIsGibberish) quality -= 2;
if (bioIsShort) quality -= 1;
if (!bio && !statement) quality -= 3;
if (websiteDomain) quality += 2;
if (emailDomain) quality += 1;
if (city) quality += 1;
quality = Math.max(0, Math.min(10, quality));

const anchors = [];
if (websiteDomain) anchors.push('Website domain: ' + websiteDomain);
if (emailDomain) anchors.push('Email domain: ' + emailDomain);
if (city && state) anchors.push('Location: ' + city + ', ' + state);
else if (city) anchors.push('Location: ' + city);
else if (state) anchors.push('Location: ' + state);

const identityContext = anchors.length > 0 ? anchors.join('; ') : 'No strong identity anchors available';

let qualityWarning = '';
if (bioIsGibberish && statementIsGibberish) {
  qualityWarning = 'WARNING: Both bio and artist statement are placeholder/gibberish text. Do NOT use them as research context. Focus research entirely on the website, email domain, and name + location searches.';
} else if (bioIsGibberish) {
  qualityWarning = 'WARNING: Bio is placeholder text. Rely on the artist statement, website, and other identity anchors for research context.';
} else if (statementIsGibberish) {
  qualityWarning = 'NOTE: Artist statement is placeholder text. Rely on bio, website, and other identity anchors.';
} else if (bioIsShort) {
  qualityWarning = 'NOTE: Bio is very short. Supplement with web research from website and other sources.';
}

return [{
  json: {
    ...item,
    _dataQuality: quality,
    _bioIsGibberish: bioIsGibberish,
    _statementIsGibberish: statementIsGibberish,
    _emailDomain: emailDomain,
    _websiteDomain: websiteDomain,
    _identityContext: identityContext,
    _qualityWarning: qualityWarning
  }
}];

const artists = $input.all();
const totalArtists = artists.length;
const now = new Date().toISOString();
const datePart = now.split('T')[0];
const seq = String(Math.floor(Math.random() * 999)).padStart(3, '0');
const runId = `enrich-${datePart}-${seq}`;

return [{
  json: {
    runId,
    totalArtists,
    startedAt: now,
    actionRecordId: 'rec0MY5HBTWKtmayb'
  }
}];

const runRecordId = $('Create Pipeline Run').first().json.id;
const actionRecordId = 'rec0MY5HBTWKtmayb';
const totalArtists = $('Prepare Run Metadata').first().json.totalArtists;
const artists = $('Find Pending Artists').all();

return artists.map(item => ({
  json: {
    ...item.json,
    _runRecordId: runRecordId,
    _actionRecordId: actionRecordId,
    _totalArtists: totalArtists
  }
}));

const staticData = $getWorkflowStaticData('global');
staticData.processedArtists = (staticData.processedArtists || 0) + 1;
const current = staticData.processedArtists;
const total = $('Restore Artist Data').first().json._totalArtists;
const artistName = $('Find Pending Artists').item.json['Full Name'] || $input.item.json.fields?.['Full Name'] || 'Unknown';
const remaining = total - current;
const estMinutes = remaining * 3;

return [{
  json: {
    _runRecordId: $('Restore Artist Data').first().json._runRecordId,
    _actionRecordId: $('Restore Artist Data').first().json._actionRecordId,
    processedArtists: current,
    totalArtists: total,
    currentRecord: artistName,
    progressSummary: `Artist ${current} of ${total} \u2014 ${artistName}`,
    estTimeRemaining: estMinutes > 0 ? `~${estMinutes} minutes` : 'Almost done'
  }
}];

const staticData = $getWorkflowStaticData('global');
staticData.processedArtworks = 0;
const artworks = $input.all();
const totalArtworks = artworks.length;
staticData.totalArtworks = totalArtworks;

return artworks.map(item => ({
  json: {
    ...item.json,
    _totalArtworks: totalArtworks,
    _runRecordId: $('Restore Artist Data').first().json._runRecordId,
    _actionRecordId: $('Restore Artist Data').first().json._actionRecordId
  }
}));

const staticData = $getWorkflowStaticData('global');
staticData.processedArtworks = (staticData.processedArtworks || 0) + 1;
const current = staticData.processedArtworks;
const total = staticData.totalArtworks || 0;
const artworkName = $input.item.json.fields?.['Piece Name'] || $input.item.json['Piece Name'] || 'Unknown';
const remaining = total - current;
const estSeconds = remaining * 20;

return [{
  json: {
    _actionRecordId: $('Restore Artist Data').first().json._actionRecordId,
    processedArtworks: current,
    totalArtworks: total,
    currentRecord: artworkName,
    progressSummary: `Artwork ${current} of ${total} \u2014 ${artworkName}`,
    estTimeRemaining: estSeconds > 60 ? `~${Math.ceil(estSeconds / 60)} minutes` : (estSeconds > 0 ? `~${estSeconds} seconds` : 'Almost done')
  }
}];

const staticData = $getWorkflowStaticData('global');
const processedArtists = staticData.processedArtists || 0;
const processedArtworks = staticData.processedArtworks || 0;
const totalArtists = $('Restore Artist Data').first().json._totalArtists || 0;
const totalArtworks = staticData.totalArtworks || 0;
const now = new Date().toISOString();

// Reset static data for next run
staticData.processedArtists = 0;
staticData.processedArtworks = 0;
staticData.totalArtworks = 0;

return [{
  json: {
    _runRecordId: $('Restore Artist Data').first().json._runRecordId,
    _actionRecordId: $('Restore Artist Data').first().json._actionRecordId,
    completedAt: now,
    processedArtists,
    processedArtworks,
    totalArtists,
    totalArtworks,
    finalSummary: `Completed: ${processedArtists} artists, ${processedArtworks} artworks`,
    lastRunSummary: `Last run: ${processedArtists} artists, ${processedArtworks} artworks`
  }
}];

